// Parse NewsAPI JSON response
const items = data.map(item => ({
  id: `newsapi-${Buffer.from(item.title + item.url).toString('base64')}`,
  title: item.title,
  summary: item.description,
  body: item.content,
  link: item.url,
  source: item.source.name,
  source_tier: 1,
  published_date: item.publishedAt,
  language: 'en',
  ingested_at: new Date().toISOString()
}));
return items;

// Parse RSS feed XML to JSON
const parseRss = (xmlText) => {
  const rssItems = xmlText.match(/<item>.*?<\/item>/gs) || [];
  return rssItems.map(item => {
    const title = item.match(/<title>(.*?)<\/title>/)?.[1] || '';
    const link = item.match(/<link>(.*?)<\/link>/)?.[1] || '';
    const description = item.match(/<description>(.*?)<\/description>/)?.[1] || '';
    const pubDate = item.match(/<pubDate>(.*?)<\/pubDate>/)?.[1] || new Date().toISOString();
    return {
      id: `rss-${Buffer.from(title + link).toString('base64')}`,
      title,
      summary: description.substring(0, 200),
      body: description,
      link,
      source: 'RSS Tier 1',
      source_tier: 1,
      published_date: pubDate,
      language: 'en',
      ingested_at: new Date().toISOString()
    };
  });
};
return parseRss(data);

// Combine all feed items and deduplicate
const allItems = input.all();
const combinedItems = [];

// Flatten from multiple sources
allItems.forEach(node => {
  if (Array.isArray(node)) combinedItems.push(...node);
  else combinedItems.push(node);
});

// Deduplicate by hash
const seen = new Set();
const deduped = [];
const duplicates = [];

combinedItems.forEach(item => {
  const hash = require('crypto')
    .createHash('sha256')
    .update(item.title + item.link)
    .digest('hex');

  if (seen.has(hash)) {
    duplicates.push({...item, hash, duplicate_of: hash});
  } else {
    deduped.push({...item, hash, duplicate_of: null});
    seen.add(hash);
  }
});

return {
  novel_items: deduped,
  duplicate_items: duplicates,
  total_ingested: combinedItems.length,
  novel_count: deduped.length,
  duplicate_count: duplicates.length
};

