{
  "records": [
    {% for item of $json.novel_items %}
    {
      "fields": {
        "title": "{{ item.title }}",
        "summary": "{{ item.summary }}",
        "link": "{{ item.link }}",
        "source": "{{ item.source }}",
        "source_tier": {{ item.source_tier }},
        "published_date": "{{ item.published_date }}",
        "ingested_at": "{{ item.ingested_at }}",
        "hash": "{{ item.hash }}",
        "status": "PENDING_SCORE"
      }
    }{{ ',' if not loop.last }}
    {% endfor %}
  ]
}
